173		if len(files) == 0 {
174			return
175		}
176		list := make([]string, 0, len(files))
177		for f := range files {
178			list = append(list, f)
179		}
180		// Non-blocking send; drop if consumer is too slow.
181		select {
182		case fw.events <- WatchEvent{RepoPath: repo, Files: list}:
183		default:
184		}
