1	package daemon
2	
3	import (
4		"bufio"
5		"context"
6		"database/sql"
7		"fmt"
8		"os"
9		"path/filepath"
10		"strings"
11		"sync"
12		"time"
13	
14		"github.com/blackwell-systems/knowing/internal/cache"
15		"github.com/blackwell-systems/knowing/internal/community"
16		"github.com/blackwell-systems/knowing/internal/snapshot"
17		"github.com/blackwell-systems/knowing/internal/trace"
18		"github.com/blackwell-systems/knowing/internal/types"
19		_ "modernc.org/sqlite"
20	)
21	
22	// The Daemon is the long-running process that ties together file watching,
23	// incremental reindexing, LSP enrichment, and MCP query serving. It runs
24	// three concurrent goroutines:
25	//
26	//  1. watchLoop: reads CommitEvents from GitWatcher and enqueues index requests
27	//  2. indexWorker: processes index requests sequentially (holding a write lock)
28	//  3. MCP server: serves graph queries over HTTP (concurrent reads allowed)
29	//
30	// The write lock ensures readers always see a consistent graph state:
31	// queries block during indexing, and indexing blocks during queries.
32	
33	// MCPServer abstracts the MCP transport so the daemon does not import the
34	// MCP package directly.
35	type MCPServer interface {
36		ServeStdio(ctx context.Context) error
37		ServeHTTP(ctx context.Context, addr string) error
38	}
39	
40	// DaemonConfig holds all dependencies the daemon needs, injected as
41	// interfaces and callbacks to avoid tight coupling to concrete packages.
42	type DaemonConfig struct {
43		Store     types.GraphStore
44		IndexFunc func(ctx context.Context, repoURL, repoPath, commitHash string, changedFiles []string) error
45		MCPAddr   string
46		MCPServer MCPServer
47	
48		// EnrichFunc is called in the background after each successful index run.
49		// It receives the repo hash and workspace root path to run LSP enrichment.
50		// If nil, enrichment is skipped.
51		EnrichFunc func(ctx context.Context, repoHash types.Hash, workspaceRoot string, changedFiles []string) error
52	
53		// TraceConfig holds configuration for the runtime trace ingestion pipeline.
54		// If nil or Enabled is false, trace ingestion is not started.
55		TraceConfig *TraceIngestConfig
56	
57		// DBPath is the path to the SQLite database file, used by the trace
58		// ingestor for direct DB access. Must be set when TraceConfig is enabled.
59		DBPath string
60	
61		// SnapMgr is the SnapshotManager used to obtain the most recently computed
62		// HierarchicalTree after each index run. Required for cache invalidation.
63		// If nil, cache invalidation is skipped.
64		SnapMgr *snapshot.SnapshotManager
65	
66		// ResultCache is the SubgraphCache to invalidate after each successful index.
67		// If nil, no cache invalidation occurs.
68		ResultCache *cache.SubgraphCache
69	}
70	
71	// TraceIngestConfig holds configuration for the runtime trace ingestion pipeline.
72	type TraceIngestConfig struct {
73		Enabled       bool
74		OTLPEndpoint  string
75		BatchSize     int
76		BatchInterval time.Duration
77	}
78	
79	// Daemon is the long-lived process that watches repositories for changes,
80	// triggers reindexing, and serves MCP queries.
81	type Daemon struct {
82		cfg DaemonConfig
83	
84		mu      sync.RWMutex       // protects graph consistency: write lock during indexing, read lock during queries
85		watcher *GitWatcher
86		repos   map[string]string  // repoPath -> repoURL
87	
88		cancel context.CancelFunc // cancels the daemon's root context
89		wg     sync.WaitGroup     // tracks all daemon goroutines for graceful shutdown
90	
91		indexQueue chan indexRequest // buffered channel of pending index requests
92	
93		// prevTree is the HierarchicalTree from the previous index run, used to
94		// compute a diff and invalidate stale cache entries after each reindex.
95		// Protected by mu (written during indexWorker's write-lock window).
96		prevTree *snapshot.HierarchicalTree
97	}
98	
99	type indexRequest struct {
100		repoURL      string
101		repoPath     string
102		changedFiles []string
103	}
104	
105	// NewDaemon creates a Daemon with the given configuration. Call Start to
106	// begin watching and serving.
107	func NewDaemon(cfg DaemonConfig) *Daemon {
108		return &Daemon{
109			cfg:        cfg,
110			repos:      make(map[string]string),
111			indexQueue:  make(chan indexRequest, 128),
112		}
113	}
114	
115	// Start launches the file watcher, MCP server, and index worker. It blocks
116	// until the provided context is cancelled or Stop is called.
117	func (d *Daemon) Start(ctx context.Context) error {
118		ctx, d.cancel = context.WithCancel(ctx)
119	
120		if d.cfg.DBPath != "" {
121			if err := AcquireLockfile(d.cfg.DBPath); err != nil {
122				return fmt.Errorf("daemon: %w", err)
123			}
124		}
125	
126		gw, err := NewGitWatcher(500 * time.Millisecond)
127		if err != nil {
128			return fmt.Errorf("daemon: create watcher: %w", err)
129		}
130		d.watcher = gw
131	
132		// Re-add any repos that were registered before Start.
133		d.mu.RLock()
134		for rp := range d.repos {
135			_ = gw.Add(rp)
136		}
137		d.mu.RUnlock()
138	
139		// Index worker goroutine.
140		d.wg.Add(1)
141		go func() {
142			defer d.wg.Done()
143			d.indexWorker(ctx)
144		}()
145	
146		// File change listener goroutine.
147		d.wg.Add(1)
148		go func() {
149			defer d.wg.Done()
150			d.watchLoop(ctx)
151		}()
152	
153		// MCP server goroutine (if configured).
154		if d.cfg.MCPServer != nil && d.cfg.MCPAddr != "" {
155			d.wg.Add(1)
156			go func() {
157				defer d.wg.Done()
158				_ = d.cfg.MCPServer.ServeHTTP(ctx, d.cfg.MCPAddr)
159			}()
160		}
161	
162		// Trace ingestor goroutine (if configured).
163		if d.cfg.TraceConfig != nil && d.cfg.TraceConfig.Enabled {
164			d.wg.Add(1)
165			go func() {
166				defer d.wg.Done()
167				d.traceIngestLoop(ctx)
168			}()
169		}
170	
171		// Block until context is cancelled.
172		<-ctx.Done()
173		return d.shutdown()
174	}
175	
176	// Stop triggers graceful shutdown of the daemon.
177	func (d *Daemon) Stop() error {
178		if d.cancel != nil {
179			d.cancel()
180		}
181		return nil
182	}
183	
184	// WatchRepo registers a repository directory for file watching and future
185	// reindexing. If the daemon is already running the directory is added to the
186	// live watcher immediately.
187	func (d *Daemon) WatchRepo(repoPath string) error {
188		d.mu.Lock()
189		d.repos[repoPath] = repoPath // URL defaults to path; callers can set it.
190		d.mu.Unlock()
191	
192		if d.watcher != nil {
193			return d.watcher.Add(repoPath)
194		}
195		return nil
196	}
197	
198	// UnwatchRepo removes a repository from the watch list.
199	func (d *Daemon) UnwatchRepo(repoPath string) error {
200		d.mu.Lock()
201		delete(d.repos, repoPath)
202		d.mu.Unlock()
203	
204		if d.watcher != nil {
205			return d.watcher.Remove(repoPath)
206		}
207		return nil
208	}
209	
210	// GarbageCollect runs garbage collection while holding the write lock
211	// to prevent concurrent index writes during the reachability sweep.
212	// The gcFunc callback performs the actual GC work (e.g., calling
213	// SnapshotManager.GarbageCollect or GarbageCollectFull).
214	func (d *Daemon) GarbageCollect(ctx context.Context, gcFunc func(ctx context.Context) error) error {
215		d.mu.Lock()
216		defer d.mu.Unlock()
217		return gcFunc(ctx)
218	}
219	
220	// GitHeadCommit reads the HEAD commit hash from a git repository without
221	// shelling out to git. It resolves symbolic refs and falls back to packed-refs
222	// when loose ref files are missing.
223	//
224	// Git HEAD resolution works in two stages:
225	//  1. Read .git/HEAD. If it contains a raw 40-char hex hash, the repo is in
226	//     "detached HEAD" state and that hash is returned directly.
227	//  2. If HEAD contains "ref: refs/heads/main" (a symbolic ref), resolve the
228	//     ref to a commit hash by reading the loose ref file (.git/refs/heads/main).
229	//     If the loose file is missing (git may pack refs for performance), fall
230	//     back to scanning .git/packed-refs for the ref.
231	func GitHeadCommit(repoPath string) (string, error) {
232		gitDir := filepath.Join(repoPath, ".git")
233	
234		headBytes, err := os.ReadFile(filepath.Join(gitDir, "HEAD"))
235		if err != nil {
236			return "", fmt.Errorf("reading .git/HEAD: %w", err)
237		}
238		head := strings.TrimSpace(string(headBytes))
239	
240		// Detached HEAD: HEAD contains a raw 40-character commit hash.
241		if !strings.HasPrefix(head, "ref: ") {
242			if len(head) >= 40 {
243				return head[:40], nil
244			}
245			return "", fmt.Errorf("unexpected HEAD content: %s", head)
246		}
247	
248		// Symbolic ref (e.g., "ref: refs/heads/main"): resolve to commit hash.
249		ref := strings.TrimPrefix(head, "ref: ")
250	
251		// Try the loose ref file first (most common case after a commit).
252		looseRef := filepath.Join(gitDir, ref)
253		if data, err := os.ReadFile(looseRef); err == nil {
254			return strings.TrimSpace(string(data)), nil
255		}
256	
257		// Fall back to packed-refs. Git packs loose refs into this single file
258		// during gc operations. Each line is "<hash> <ref>" with comment lines
259		// starting with "#" and peel lines starting with "^".
260		packedRefsPath := filepath.Join(gitDir, "packed-refs")
261		f, err := os.Open(packedRefsPath)
262		if err != nil {
263			return "", fmt.Errorf("ref %s not found in loose refs or packed-refs: %w", ref, err)
264		}
265		defer f.Close()
266	
267		scanner := bufio.NewScanner(f)
268		for scanner.Scan() {
269			line := scanner.Text()
270			if strings.HasPrefix(line, "#") || strings.HasPrefix(line, "^") {
271				continue
272			}
273			parts := strings.SplitN(line, " ", 2)
274			if len(parts) == 2 && parts[1] == ref {
275				return parts[0], nil
276			}
277		}
278	
279		return "", fmt.Errorf("ref %s not found in packed-refs", ref)
280	}
281	
282	// RLock acquires a read lock, allowing concurrent readers.
283	func (d *Daemon) RLock() { d.mu.RLock() }
284	
285	// RUnlock releases the read lock.
286	func (d *Daemon) RUnlock() { d.mu.RUnlock() }
287	
288	// traceIngestLoop runs the trace ingestion pipeline. It opens a dedicated
289	// database connection, creates a SymbolResolver, Ingestor, and OTLPReceiver,
290	// starts the gRPC receiver, and runs periodic FlushBatch and DecayConfidence
291	// loops until the context is cancelled.
292	func (d *Daemon) traceIngestLoop(ctx context.Context) {
293		cfg := d.cfg.TraceConfig
294		if cfg == nil {
295			return
296		}
297	
298		// Open a dedicated DB connection for the trace pipeline.
299		db, err := sql.Open("sqlite", d.cfg.DBPath)
300		if err != nil {
301			return // silently fail; trace is non-critical
302		}
303		defer db.Close()
304	
305		resolver := trace.NewSymbolResolver(db)
306		traceCfg := trace.TraceIngestConfig{
307			Enabled:       cfg.Enabled,
308			OTLPEndpoint:  cfg.OTLPEndpoint,
309			BatchSize:     cfg.BatchSize,
310			BatchInterval: cfg.BatchInterval,
311		}
312		ingestor := trace.NewIngestor(db, resolver, traceCfg)
313		receiver := trace.NewOTLPReceiver(cfg.OTLPEndpoint, ingestor)
314	
315		if err := receiver.Start(ctx); err != nil {
316			return
317		}
318		defer receiver.Stop()
319	
320		// Periodic flush and decay loop.
321		batchTicker := time.NewTicker(cfg.BatchInterval)
322		defer batchTicker.Stop()
323	
324		decayInterval := 1 * time.Hour
325		decayTicker := time.NewTicker(decayInterval)
326		defer decayTicker.Stop()
327	
328		for {
329			select {
330			case <-ctx.Done():
331				_ = ingestor.FlushBatch(context.Background())
332				return
333			case <-batchTicker.C:
334				_ = ingestor.FlushBatch(ctx)
335			case <-decayTicker.C:
336				_, _ = ingestor.DecayConfidence(ctx)
337			}
338		}
339	}
340	
341	// shutdown cleans up watcher and waits for goroutines.
342	func (d *Daemon) shutdown() error {
343		if d.cfg.DBPath != "" {
344			ReleaseLockfile(d.cfg.DBPath)
345		}
346		close(d.indexQueue)
347		if d.watcher != nil {
348			_ = d.watcher.Close()
349		}
350		d.wg.Wait()
351		return nil
352	}
353	
354	// watchLoop reads commit events from GitWatcher and enqueues index requests.
355	func (d *Daemon) watchLoop(ctx context.Context) {
356		if d.watcher == nil {
357			return
358		}
359		for {
360			select {
361			case <-ctx.Done():
362				return
363			case ev, ok := <-d.watcher.Events():
364				if !ok {
365					return
366				}
367				d.mu.RLock()
368				repoURL := d.repos[ev.RepoPath]
369				d.mu.RUnlock()
370				if repoURL == "" {
371					repoURL = ev.RepoPath
372				}
373				// Combine all changed paths for downstream consumers.
374				allChanged := make([]string, 0, len(ev.ChangedFiles)+len(ev.AddedFiles)+len(ev.DeletedFiles))
375				allChanged = append(allChanged, ev.ChangedFiles...)
376				allChanged = append(allChanged, ev.AddedFiles...)
377				allChanged = append(allChanged, ev.DeletedFiles...)
378				select {
379				case d.indexQueue <- indexRequest{
380					repoURL:      repoURL,
381					repoPath:     ev.RepoPath,
382					changedFiles: allChanged,
383				}:
384				default:
385					// Queue full; skip this event.
386				}
387			}
388		}
389	}
390	
391	// indexWorker processes index requests sequentially from the indexQueue channel.
392	// It holds the daemon's write lock during indexing to ensure readers see a
393	// consistent graph state. After each successful index, it spawns a background
394	// goroutine for LSP enrichment (which does not hold the write lock) and
395	// invalidates stale subgraph cache entries using the HierarchicalTree diff.
396	func (d *Daemon) indexWorker(ctx context.Context) {
397		for req := range d.indexQueue {
398			if ctx.Err() != nil {
399				return
400			}
401			if d.cfg.IndexFunc == nil {
402				continue
403			}
404			// Resolve HEAD commit hash; fall back to "unknown" if not a git repo.
405			commit, err := GitHeadCommit(req.repoPath)
406			if err != nil {
407				commit = "unknown"
408			}
409			// Acquire write lock during indexing so readers wait.
410			d.mu.Lock()
411			indexErr := d.cfg.IndexFunc(ctx, req.repoURL, req.repoPath, commit, req.changedFiles)
412	
413			// After a successful index: compute Merkle diff, invalidate cache,
414			// and run incremental community detection. All inside the write lock
415			// so readers see consistent state.
416			var changedPkgs []string
417			if indexErr == nil && d.cfg.SnapMgr != nil {
418				newTree := d.cfg.SnapMgr.LastHierarchicalTree()
419				if newTree != nil {
420					if d.prevTree != nil {
421						diff := snapshot.DiffHierarchicalTrees(d.prevTree, newTree)
422						changedPkgs = make([]string, 0,
423							len(diff.ChangedPackages)+len(diff.AddedPackages)+len(diff.RemovedPackages))
424						changedPkgs = append(changedPkgs, diff.ChangedPackages...)
425						changedPkgs = append(changedPkgs, diff.AddedPackages...)
426						changedPkgs = append(changedPkgs, diff.RemovedPackages...)
427						if len(changedPkgs) > 0 && d.cfg.ResultCache != nil {
428							d.cfg.ResultCache.InvalidatePackages(changedPkgs, newTree)
429						}
430					}
431					d.prevTree = newTree
432				}
433			}
434	
435			// Incremental community detection (Phase 3 P3):
436			// Use changedPkgs from the Merkle diff to scope detection.
437			if indexErr == nil && d.cfg.Store != nil {
438				d.runIncrementalCommunities(ctx, req.repoURL, changedPkgs)
439			}
440	
441			// Scoped FTS rebuild (Phase 3 P4):
442			// Rebuild BM25 index only for changed packages instead of full table.
443			if indexErr == nil && len(changedPkgs) > 0 {
444				if ftsStore, ok := d.cfg.Store.(interface {
445					RebuildFTSForPackages(ctx context.Context, packages []string) error
446				}); ok {
447					_ = ftsStore.RebuildFTSForPackages(ctx, changedPkgs)
448				}
449			}
450	
451			d.mu.Unlock()
452	
453			// Trigger background enrichment after successful index.
454			if indexErr == nil && d.cfg.EnrichFunc != nil {
455				repoHash := types.NewHash([]byte(req.repoURL))
456				d.wg.Add(1)
457				go func() {
458					defer d.wg.Done()
459					_ = d.cfg.EnrichFunc(ctx, repoHash, req.repoPath, req.changedFiles)
460				}()
461			}
462		}
463	}
464	
465	// runIncrementalCommunities loads previous community assignments from notes,
466	// builds the graph, marks nodes in changedPkgs as changed, and runs
467	// incremental detection. Results are persisted back to notes for the next run.
468	//
469	// changedPkgs comes from the Merkle diff (ChangedPackages + AddedPackages +
470	// RemovedPackages). If nil, all nodes are treated as changed (full detection).
471	//
472	// Must be called inside the write lock (d.mu held for write).
473	func (d *Daemon) runIncrementalCommunities(ctx context.Context, repoURL string, changedPkgs []string) {
474		nodes, err := d.cfg.Store.NodesByName(ctx, repoURL)
475		if err != nil || len(nodes) == 0 {
476			return
477		}
478	
479		// Build adjacency list.
480		nodeSet := make(map[types.Hash]bool, len(nodes))
481		nodeHashes := make([]types.Hash, len(nodes))
482		for i, n := range nodes {
483			nodeSet[n.NodeHash] = true
484			nodeHashes[i] = n.NodeHash
485		}
486	
487		adj := make(map[types.Hash][]community.WeightedEdge, len(nodes))
488		edgeCount := 0
489		maxNodes := len(nodes)
490		if maxNodes > 5000 {
491			maxNodes = 5000
492		}
493		for i := 0; i < maxNodes; i++ {
494			edges, err := d.cfg.Store.EdgesFrom(ctx, nodes[i].NodeHash, "")
495			if err != nil {
496				continue
497			}
498			for _, e := range edges {
499				if !nodeSet[e.TargetHash] {
500					continue
501				}
502				adj[nodes[i].NodeHash] = append(adj[nodes[i].NodeHash], community.WeightedEdge{
503					Target: e.TargetHash, Weight: e.Confidence,
504				})
505				adj[e.TargetHash] = append(adj[e.TargetHash], community.WeightedEdge{
506					Target: nodes[i].NodeHash, Weight: e.Confidence,
507				})
508				edgeCount++
509			}
510		}
511	
512		g := &community.Graph{
513			Nodes:     nodeHashes,
514			Adj:       adj,
515			NodeSet:   nodeSet,
516			EdgeCount: edgeCount,
517		}
518	
519		algo := community.Get(community.Default)
520		incAlgo, ok := algo.(community.IncrementalAlgorithm)
521		if !ok {
522			membership := algo.Detect(g)
523			_ = community.SaveAssignments(ctx, d.cfg.Store, membership)
524			return
525		}
526	
527		previous, _ := community.LoadAssignments(ctx, d.cfg.Store)
528	
529		// Build changed node set from changed packages.
530		// A node is changed if: (a) its qualified name contains a changed package,
531		// or (b) it's new (not in previous assignments).
532		changedNodes := make(map[types.Hash]bool)
533		if previous != nil && len(changedPkgs) > 0 {
534			// Build a set for fast lookup.
535			pkgSet := make(map[string]bool, len(changedPkgs))
536			for _, p := range changedPkgs {
537				pkgSet[p] = true
538			}
539			// Mark nodes whose package is in the changed set.
540			for _, n := range nodes {
541				if _, inPrev := previous[n.NodeHash]; !inPrev {
542					changedNodes[n.NodeHash] = true
543					continue
544				}
545				// Check if node's qualified name starts with any changed package.
546				for _, pkg := range changedPkgs {
547					if len(n.QualifiedName) >= len(pkg) && n.QualifiedName[:len(pkg)] == pkg {
548						changedNodes[n.NodeHash] = true
549						break
550					}
551				}
552			}
553		} else {
554			// No previous or no diff: all nodes changed (full detection).
555			for _, h := range nodeHashes {
556				changedNodes[h] = true
557			}
558		}
559	
560		var membership map[types.Hash]int
561		if len(changedNodes) > 0 {
562			membership = incAlgo.DetectIncremental(g, previous, changedNodes)
563		} else if previous != nil {
564			membership = previous
565		} else {
566			membership = algo.Detect(g)
567		}
568	
569		// Delta-save: only write assignments that changed.
570		if previous != nil {
571			_ = community.SaveChangedAssignments(ctx, d.cfg.Store, membership, previous)
572		} else {
573			_ = community.SaveAssignments(ctx, d.cfg.Store, membership)
574		}
575	}
